import { z } from "zod";

import { buildCoachMessages } from "@/lib/contextBuilder";
import { callJudgeJSONWithFallback } from "@/lib/judgeClient";
import { CoachResultSchema } from "@/lib/schemas";
import { getSession, saveSession } from "@/lib/session";

const CoachRequestSchema = z.object({
  sessionId: z.string().min(1),
});

export async function POST(request: Request) {
  const body = await request.json();
  const parsed = CoachRequestSchema.safeParse(body);
  if (!parsed.success) {
    return Response.json({ error: "Invalid coach request." }, { status: 400 });
  }

  const session = getSession(parsed.data.sessionId);
  if (!session) {
    return Response.json({ error: "Session not found." }, { status: 404 });
  }

  try {
    const coach = await callJudgeJSONWithFallback({
      messages: buildCoachMessages(session, "hint_request"),
      schema: CoachResultSchema,
      temperature: 0.2,
      jsonRetries: 1,
      rateLimitRetriesPerModel: 1,
    });

    session.coachNudgeCount += 1;
    session.lastCoachTurnIndex = session.turnIntents.length - 1;
    session.pendingHintPenalty = (session.pendingHintPenalty ?? 0) + 0.5;
    saveSession(session);

    return Response.json(coach);
  } catch (error) {
    console.error("Coach request failed:", error);
    return Response.json({ error: "Failed to generate coach nudge." }, { status: 502 });
  }
}
