import type { ZodType } from "zod";

import {
  callJSONValidated,
  callOpenRouter,
  extractRetryAfterSeconds,
  isNoEndpointError,
  isRateLimitError,
} from "@/lib/openrouter";
import type { ChatMessage } from "@/lib/types";

const DEFAULT_JUDGE_MODEL =
  process.env.JUDGE_MODEL ?? "meta-llama/llama-3.3-70b-instruct:free";
const DEFAULT_JUDGE_FALLBACKS = process.env.JUDGE_MODEL_FALLBACKS ?? "openrouter/free";

type JudgeFallbackOptions = {
  models?: string[];
  rateLimitRetriesPerModel?: number;
};

type JudgeJSONArgs<T> = JudgeFallbackOptions & {
  messages: ChatMessage[];
  schema: ZodType<T>;
  temperature?: number;
  jsonRetries?: number;
};

type JudgeTextArgs = JudgeFallbackOptions & {
  messages: ChatMessage[];
  temperature?: number;
};

function judgeFallbackModelsFromEnv(): string[] {
  return DEFAULT_JUDGE_FALLBACKS.split(",")
    .map((model) => model.trim())
    .filter(Boolean);
}

export function judgeModelCandidates(primaryModel = DEFAULT_JUDGE_MODEL): string[] {
  const candidates = [primaryModel, ...judgeFallbackModelsFromEnv()];
  return [...new Set(candidates)];
}

async function waitForRateLimit(seconds: number): Promise<void> {
  if (process.env.NODE_ENV === "test") {
    return;
  }
  await new Promise<void>((resolve) => {
    setTimeout(() => resolve(), Math.max(0, Math.ceil(seconds * 1000)));
  });
}

async function runWithJudgeFallback<T>(
  operation: (model: string) => Promise<T>,
  options: JudgeFallbackOptions,
): Promise<T> {
  const candidates =
    options.models && options.models.length > 0
      ? [...new Set(options.models.map((model) => model.trim()).filter(Boolean))]
      : judgeModelCandidates();
  const rateLimitRetriesPerModel = options.rateLimitRetriesPerModel ?? 1;

  let lastError: unknown;

  for (let index = 0; index < candidates.length; index += 1) {
    const model = candidates[index];
    let rateLimitAttempts = 0;

    while (true) {
      try {
        return await operation(model);
      } catch (error) {
        lastError = error;

        if (isRateLimitError(error)) {
          if (rateLimitAttempts < rateLimitRetriesPerModel) {
            rateLimitAttempts += 1;
            const retryAfterSeconds = extractRetryAfterSeconds(error);
            console.warn(
              `Judge model rate-limited (${model}). Retrying in ${retryAfterSeconds}s (${rateLimitAttempts}/${rateLimitRetriesPerModel}).`,
            );
            await waitForRateLimit(retryAfterSeconds);
            continue;
          }
          break;
        }

        if (isNoEndpointError(error)) {
          break;
        }

        throw error;
      }
    }

    if (index < candidates.length - 1) {
      console.warn(
        `Judge model unavailable (${model}). Retrying with fallback ${candidates[index + 1]}.`,
      );
    }
  }

  if (lastError instanceof Error) {
    throw lastError;
  }
  throw new Error("All judge model candidates failed.");
}

export async function callJudgeJSONWithFallback<T>({
  messages,
  schema,
  temperature = 0.2,
  jsonRetries = 1,
  ...fallbackOptions
}: JudgeJSONArgs<T>): Promise<T> {
  return runWithJudgeFallback(
    (model) =>
      callJSONValidated(
        {
          model,
          messages,
          temperature,
        },
        schema,
        jsonRetries,
      ),
    fallbackOptions,
  );
}

export async function callJudgeTextWithFallback({
  messages,
  temperature = 0.2,
  ...fallbackOptions
}: JudgeTextArgs): Promise<string> {
  return runWithJudgeFallback(
    (model) =>
      callOpenRouter({
        model,
        messages,
        temperature,
      }),
    fallbackOptions,
  );
}
